#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <unistd.h>
#include <fcntl.h>
#include <float.h>
#include <time.h>
#include <sys/time.h>

#define BLOCK_X 16
#define BLOCK_Y 16
#define PI 3.1415926535897932
#define SCALE_FACTOR 300

long M = INT_MAX;
int A = 1103515245;
int C = 12345;

int threads_per_block = 512;
int device_id_inuse = 0;
int platform_id_inuse = 0;

static long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

static double elapsed_time(long long start_time, long long end_time) {
    return (double)(end_time - start_time) / (1000.0 * 1000.0);
}

static void check_error(cudaError_t e) {
    if (e != cudaSuccess) {
        printf("\nCUDA error: %s\n", cudaGetErrorString(e));
        exit(1);
    }
}

static const char *base_name(const char *path) {
    const char *p = strrchr(path, '/');
    return p ? p + 1 : path;
}

namespace mode_double {

static double randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double)M));
}

static double randn(int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

static double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5)
        return newValue;
    else
        return newValue++;
}

static void setIf(int testValue, int newValue, unsigned char *array3D, int *dimX, int *dimY, int *dimZ) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

static void addNoise(unsigned char *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (unsigned char)(5 * randn(seed, 0));
            }
        }
    }
}

static void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

static void dilate_matrix(unsigned char *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0) startX++;
    int startY = posY - error;
    while (startY < 0) startY++;
    int endX = posX + error;
    while (endX > dimX) endX--;
    int endY = posY + error;
    while (endY > dimY) endY--;
    for (int x = startX; x < endX; x++) {
        for (int y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

static void imdilate_disk(unsigned char *matrix, int dimX, int dimY, int dimZ, int error, unsigned char *newMatrix) {
    for (int z = 0; z < dimZ; z++) {
        for (int x = 0; x < dimX; x++) {
            for (int y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1)
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
            }
        }
    }
}

static void getneighbors(int *se, int numOnes, int *neighbors, int radius) {
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

static void videoSequence(unsigned char *I, int IszX, int IszY, int Nfr, int *seed) {
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    for (int k = 1; k < Nfr; k++) {
        int xk = abs(x0 + (k - 1));
        int yk = abs(y0 - 2 * (k - 1));
        int pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size) pos = 0;
        I[pos] = 1;
    }

    unsigned char *newMatrix = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

__device__ double dev_round_double(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5f)
        return newValue;
    else
        return newValue++;
}

__device__ double d_randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % INT_MAX;
    return fabs(seed[index] / ((double)INT_MAX));
}

__device__ double d_randn(int *seed, int index) {
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

__device__ double calcLikelihoodSum(const unsigned char *I, const int *ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    for (int x = 0; x < numOnes; x++) {
        likelihoodSum +=
            (pow((double)(I[ind[index * numOnes + x]] - 100), 2) -
             pow((double)(I[ind[index * numOnes + x]] - 228), 2)) / 50.0;
    }
    return likelihoodSum;
}

__global__ void likelihood_kernel(double *arrayX, double *arrayY, double *xj, double *yj,
                                  int *ind, int *objxy, double *likelihood,
                                  unsigned char *I, double *weights, const int Nparticles,
                                  const int countOnes, const int max_size, int k,
                                  const int IszY, const int Nfr, int *seed,
                                  double *partial_sums) {
    extern __shared__ double buffer[];
    int block_id = blockIdx.x;
    int thread_id = threadIdx.x;
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int y, indX, indY;

    if (i < Nparticles) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];

        weights[i] = 1 / ((double)(Nparticles));

        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);
    }

    if (i < Nparticles) {
        for (y = 0; y < countOnes; y++) {
            indX = (int)dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            indY = (int)dev_round_double(arrayY[i]) + objxy[y * 2];
            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (ind[i * countOnes + y] >= max_size)
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes;
        weights[i] = weights[i] * exp(likelihood[i]);
    }

    buffer[thread_id] = 0.0;
    __syncthreads();

    if (i < Nparticles) buffer[thread_id] = weights[i];
    __syncthreads();

    for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
        if ((unsigned int)thread_id < s)
            buffer[thread_id] += buffer[thread_id + s];
        __syncthreads();
    }
    if (thread_id == 0) partial_sums[block_id] = buffer[0];
}

__global__ void sum_kernel(double *partial_sums, int num_blocks) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i == 0) {
        double sum = 0.0;
        for (int x = 0; x < num_blocks; x++) sum += partial_sums[x];
        partial_sums[0] = sum;
    }
}

__global__ void normalize_weights_kernel(double *weights, int Nparticles, double *partial_sums) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < Nparticles) {
        double sumWeights = partial_sums[0];
        weights[i] = weights[i] / sumWeights;
    }
}

__global__ void cdf_u_kernel(double *weights, int Nparticles, double *CDF, double *u, int *seed) {
    if (blockIdx.x == 0 && threadIdx.x == 0) {
        if (Nparticles > 0) {
            CDF[0] = weights[0];
            for (int x = 1; x < Nparticles; x++) CDF[x] = weights[x] + CDF[x - 1];
            u[0] = (1 / ((double)(Nparticles))) * d_randu(seed, 0);
            for (int i = 0; i < Nparticles; i++) u[i] = u[0] + i / ((double)(Nparticles));
        }
    }
}

__global__ void find_index_kernel(double *arrayX, double *arrayY, double *CDF, double *u,
                                  double *xj, double *yj, double *weights, int Nparticles) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < Nparticles) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) index = Nparticles - 1;
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
        (void)weights;
    }
}

static int particleFilter(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)calloc(diameter * diameter, sizeof(int));
    strelDisk(disk, radius);
    int countOnes = 0;
    for (int x = 0; x < diameter; x++)
        for (int y = 0; y < diameter; y++)
            if (disk[x * diameter + y] == 1) countOnes++;

    int *objxy = (int *)calloc(countOnes * 2, sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    double *weights = (double *)calloc(Nparticles, sizeof(double));
    for (int x = 0; x < Nparticles; x++) weights[x] = 1 / ((double)(Nparticles));

    double *likelihood = (double *)calloc(Nparticles + 1, sizeof(double));
    double *arrayX = (double *)calloc(Nparticles, sizeof(double));
    double *arrayY = (double *)calloc(Nparticles, sizeof(double));
    double *xj = (double *)calloc(Nparticles, sizeof(double));
    double *yj = (double *)calloc(Nparticles, sizeof(double));
    double *CDF = (double *)calloc(Nparticles, sizeof(double));
    int *ind = (int *)calloc(countOnes, sizeof(int));
    double *u = (double *)calloc(Nparticles, sizeof(double));

    check_error(cudaSetDevice(device_id_inuse));
    int devcount = 0;
    cudaGetDeviceCount(&devcount);
    printf("number of available platforms:%d.\n", devcount > 0 ? 1 : 0);
    printf("clGetPlatformInfo: NVIDIA CUDA\n");

    cudaDeviceProp prop;
    check_error(cudaGetDeviceProperties(&prop, device_id_inuse));
    if ((int)prop.maxThreadsPerBlock < threads_per_block) threads_per_block = prop.maxThreadsPerBlock;

    double *arrayX_GPU;
    double *arrayY_GPU;
    double *xj_GPU;
    double *yj_GPU;
    double *CDF_GPU;
    double *likelihood_GPU;
    unsigned char *I_GPU;
    double *weights_GPU;
    int *objxy_GPU;
    int *ind_GPU;
    double *u_GPU;
    int *seed_GPU;

    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);
    if (num_blocks < 1) num_blocks = 1;
    double *partial_sums_GPU;

    check_error(cudaMalloc((void **)&arrayX_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&arrayY_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&xj_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&yj_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&CDF_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&u_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&likelihood_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&weights_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&I_GPU, sizeof(unsigned char) * IszX * IszY * Nfr));
    check_error(cudaMalloc((void **)&objxy_GPU, sizeof(int) * 2 * countOnes));
    check_error(cudaMalloc((void **)&ind_GPU, sizeof(int) * countOnes * Nparticles));
    check_error(cudaMalloc((void **)&seed_GPU, sizeof(int) * Nparticles));
    check_error(cudaMalloc((void **)&partial_sums_GPU, sizeof(double) * num_blocks));

    for (int x = 0; x < Nparticles; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    long long send_start = get_time();
    check_error(cudaMemcpy(I_GPU, I, sizeof(unsigned char) * IszX * IszY * Nfr, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(objxy_GPU, objxy, sizeof(int) * 2 * countOnes, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(weights_GPU, weights, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(xj_GPU, xj, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(yj_GPU, yj, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(seed_GPU, seed, sizeof(int) * Nparticles, cudaMemcpyHostToDevice));
    long long send_end = get_time();

    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_end));
    printf("threads_per_block=%d \n", threads_per_block);

    for (int k = 1; k < Nfr; k++) {
        likelihood_kernel<<<num_blocks, threads_per_block, threads_per_block * sizeof(double)>>>(
            arrayX_GPU, arrayY_GPU, xj_GPU, yj_GPU, ind_GPU, objxy_GPU, likelihood_GPU, I_GPU,
            weights_GPU, Nparticles, countOnes, max_size, k, IszY, Nfr, seed_GPU, partial_sums_GPU);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());

        sum_kernel<<<num_blocks, threads_per_block>>>(partial_sums_GPU, num_blocks);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());

        normalize_weights_kernel<<<num_blocks, threads_per_block>>>(weights_GPU, Nparticles, partial_sums_GPU);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());

        cdf_u_kernel<<<1, 1>>>(weights_GPU, Nparticles, CDF_GPU, u_GPU, seed_GPU);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());

        check_error(cudaMemcpy(arrayX, arrayX_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
        check_error(cudaMemcpy(arrayY, arrayY_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
        check_error(cudaMemcpy(weights, weights_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));

        xe = 0;
        ye = 0;
        double total = 0.0;
        for (int x = 0; x < Nparticles; x++) {
            xe += arrayX[x] * weights[x];
            ye += arrayY[x] * weights[x];
            total += weights[x];
        }
        printf("total weight: %lf\n", total);
        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2) +
                               pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2));
        printf("%lf\n", distance);

        find_index_kernel<<<num_blocks, threads_per_block>>>(
            arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, weights_GPU, Nparticles);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());
    }

    long long back_time = get_time();

    cudaFree(u_GPU);
    cudaFree(CDF_GPU);
    cudaFree(yj_GPU);
    cudaFree(xj_GPU);
    cudaFree(likelihood_GPU);
    cudaFree(I_GPU);
    cudaFree(objxy_GPU);
    cudaFree(ind_GPU);
    cudaFree(seed_GPU);
    cudaFree(partial_sums_GPU);

    long long free_time = get_time();

    check_error(cudaMemcpy(arrayX, arrayX_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayX_time = get_time();
    check_error(cudaMemcpy(arrayY, arrayY_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayY_time = get_time();
    check_error(cudaMemcpy(weights, weights_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
    long long back_end_time = get_time();

    printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("SEND TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));

    xe = 0;
    ye = 0;
    for (int x = 0; x < Nparticles; x++) {
        xe = xe + (arrayX[x] * weights[x]);
        ye += arrayY[x] * weights[x];
    }
    double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2) +
                           pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2));

    FILE *fid = fopen("output.txt", "w+");
    if (fid == NULL) {
        printf("The file was not opened for writing\n");
        return -1;
    }
    fprintf(fid, "XE: %lf\n", xe);
    fprintf(fid, "YE: %lf\n", ye);
    fprintf(fid, "distance: %lf\n", distance);
    fclose(fid);

    cudaFree(weights_GPU);
    cudaFree(arrayY_GPU);
    cudaFree(arrayX_GPU);

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);

    return 0;
}

static int run(int argc, char *argv[]) {
    const char *usage = "double.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles> [-p platform] [-d device]";

    if (argc < 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    for (int i = 9; i < argc; ++i) {
        switch (argv[i][1]) {
            case 'p':
                if (++i < argc) sscanf(argv[i], "%d", &platform_id_inuse);
                break;
            case 'd':
                if (++i < argc) sscanf(argv[i], "%d", &device_id_inuse);
                break;
            default:
                ;
        }
    }

    int *seed = (int *)calloc(Nparticles, sizeof(int));
    for (int i = 0; i < Nparticles; i++) seed[i] = i + 1;

    unsigned char *I = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));

    long long start = get_time();
    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}

} // namespace mode_double

namespace mode_float {

static float randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((float)M));
}

static float randn(int *seed, int index) {
    float u = randu(seed, index);
    float v = randu(seed, index);
    float cosine = cosf(2 * (float)PI * v);
    float rt = -2 * logf(u);
    return sqrtf(rt) * cosine;
}

static float roundFloat(float value) {
    int newValue = (int)(value);
    if (value - newValue < .5f)
        return newValue;
    else
        return newValue++;
}

static void setIf(int testValue, int newValue, unsigned char *array3D, int *dimX, int *dimY, int *dimZ) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

static void addNoise(unsigned char *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (unsigned char)(5 * randn(seed, 0));
            }
        }
    }
}

static void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            float distance = sqrtf(powf((float)(x - radius + 1), 2) + powf((float)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

static void dilate_matrix(unsigned char *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0) startX++;
    int startY = posY - error;
    while (startY < 0) startY++;
    int endX = posX + error;
    while (endX > dimX) endX--;
    int endY = posY + error;
    while (endY > dimY) endY--;
    for (int x = startX; x < endX; x++) {
        for (int y = startY; y < endY; y++) {
            float distance = sqrtf(powf((float)(x - posX), 2) + powf((float)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

static void imdilate_disk(unsigned char *matrix, int dimX, int dimY, int dimZ, int error, unsigned char *newMatrix) {
    for (int z = 0; z < dimZ; z++) {
        for (int x = 0; x < dimX; x++) {
            for (int y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1)
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
            }
        }
    }
}

static void getneighbors(int *se, int numOnes, int *neighbors, int radius) {
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

static void videoSequence(unsigned char *I, int IszX, int IszY, int Nfr, int *seed) {
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundFloat(IszY / 2.0f);
    int y0 = (int)roundFloat(IszX / 2.0f);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    for (int k = 1; k < Nfr; k++) {
        int xk = abs(x0 + (k - 1));
        int yk = abs(y0 - 2 * (k - 1));
        int pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size) pos = 0;
        I[pos] = 1;
    }

    unsigned char *newMatrix = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

__device__ float dev_round_float(float value) {
    int newValue = (int)(value);
    if (value - newValue < .5f)
        return newValue;
    else
        return newValue++;
}

__device__ float d_randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % INT_MAX;
    return fabs(seed[index] / ((float)INT_MAX));
}

__device__ float d_randn(int *seed, int index) {
    float u = d_randu(seed, index);
    float v = d_randu(seed, index);
    float cosine = cosf(2 * (float)PI * v);
    float rt = -2 * logf(u);
    return sqrtf(rt) * cosine;
}

__device__ float calcLikelihoodSum(const unsigned char *I, const int *ind, int numOnes, int index) {
    float likelihoodSum = 0.0f;
    for (int x = 0; x < numOnes; x++) {
        likelihoodSum +=
            (powf((float)(I[ind[index * numOnes + x]] - 100), 2) -
             powf((float)(I[ind[index * numOnes + x]] - 228), 2)) / 50.0f;
    }
    return likelihoodSum;
}

__global__ void likelihood_kernel(float *arrayX, float *arrayY, float *xj, float *yj,
                                  int *ind, int *objxy, float *likelihood,
                                  unsigned char *I, float *weights, const int Nparticles,
                                  const int countOnes, const int max_size, int k,
                                  const int IszY, const int Nfr, int *seed,
                                  float *partial_sums) {
    extern __shared__ float buffer[];
    int block_id = blockIdx.x;
    int thread_id = threadIdx.x;
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int y, indX, indY;

    if (i < Nparticles) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];

        weights[i] = 1 / ((float)(Nparticles));

        arrayX[i] = arrayX[i] + 1.0f + 5.0f * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0f + 2.0f * d_randn(seed, i);
    }

    if (i < Nparticles) {
        for (y = 0; y < countOnes; y++) {
            indX = (int)dev_round_float(arrayX[i]) + objxy[y * 2 + 1];
            indY = (int)dev_round_float(arrayY[i]) + objxy[y * 2];
            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (ind[i * countOnes + y] >= max_size)
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes - SCALE_FACTOR;
        weights[i] = weights[i] * expf(likelihood[i]);
    }

    buffer[thread_id] = 0.0f;
    __syncthreads();

    if (i < Nparticles) buffer[thread_id] = weights[i];
    __syncthreads();

    for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
        if ((unsigned int)thread_id < s)
            buffer[thread_id] += buffer[thread_id + s];
        __syncthreads();
    }
    if (thread_id == 0) partial_sums[block_id] = buffer[0];
}

__global__ void sum_kernel(float *partial_sums, int num_blocks) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i == 0) {
        float sum = 0.0f;
        for (int x = 0; x < num_blocks; x++) sum += partial_sums[x];
        partial_sums[0] = sum;
    }
}

__global__ void normalize_weights_kernel(float *weights, int Nparticles, float *partial_sums) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < Nparticles) {
        float sumWeights = partial_sums[0];
        weights[i] = weights[i] / sumWeights;
    }
}

__global__ void cdf_u_kernel(float *weights, int Nparticles, float *CDF, float *u, int *seed) {
    if (blockIdx.x == 0 && threadIdx.x == 0) {
        if (Nparticles > 0) {
            CDF[0] = weights[0];
            for (int x = 1; x < Nparticles; x++) CDF[x] = weights[x] + CDF[x - 1];
            u[0] = (1 / ((float)(Nparticles))) * d_randu(seed, 0);
            for (int i = 0; i < Nparticles; i++) u[i] = u[0] + i / ((float)(Nparticles));
        }
    }
}

__global__ void find_index_kernel(float *arrayX, float *arrayY, float *CDF, float *u,
                                  float *xj, float *yj, float *weights, int Nparticles) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < Nparticles) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) index = Nparticles - 1;
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
        (void)weights;
    }
}

static int particleFilter(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;

    float xe = roundFloat(IszY / 2.0f);
    float ye = roundFloat(IszX / 2.0f);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)calloc(diameter * diameter, sizeof(int));
    strelDisk(disk, radius);
    int countOnes = 0;
    for (int x = 0; x < diameter; x++)
        for (int y = 0; y < diameter; y++)
            if (disk[x * diameter + y] == 1) countOnes++;

    int *objxy = (int *)calloc(countOnes * 2, sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    float *weights = (float *)calloc(Nparticles, sizeof(float));
    for (int x = 0; x < Nparticles; x++) weights[x] = 1 / ((float)(Nparticles));

    float *likelihood = (float *)calloc(Nparticles + 1, sizeof(float));
    float *arrayX = (float *)calloc(Nparticles, sizeof(float));
    float *arrayY = (float *)calloc(Nparticles, sizeof(float));
    float *xj = (float *)calloc(Nparticles, sizeof(float));
    float *yj = (float *)calloc(Nparticles, sizeof(float));
    float *CDF = (float *)calloc(Nparticles, sizeof(float));
    int *ind = (int *)calloc(countOnes, sizeof(int));
    float *u = (float *)calloc(Nparticles, sizeof(float));

    check_error(cudaSetDevice(device_id_inuse));
    int devcount = 0;
    cudaGetDeviceCount(&devcount);
    printf("number of available platforms:%d.\n", devcount > 0 ? 1 : 0);
    printf("clGetPlatformInfo: NVIDIA CUDA\n");

    cudaDeviceProp prop;
    check_error(cudaGetDeviceProperties(&prop, device_id_inuse));
    if ((int)prop.maxThreadsPerBlock < threads_per_block) threads_per_block = prop.maxThreadsPerBlock;

    float *arrayX_GPU;
    float *arrayY_GPU;
    float *xj_GPU;
    float *yj_GPU;
    float *CDF_GPU;
    float *likelihood_GPU;
    unsigned char *I_GPU;
    float *weights_GPU;
    int *objxy_GPU;
    int *ind_GPU;
    float *u_GPU;
    int *seed_GPU;

    int num_blocks = (int)ceil((float)Nparticles / (float)threads_per_block);
    if (num_blocks < 1) num_blocks = 1;
    float *partial_sums_GPU;

    check_error(cudaMalloc((void **)&arrayX_GPU, sizeof(float) * Nparticles));
    check_error(cudaMalloc((void **)&arrayY_GPU, sizeof(float) * Nparticles));
    check_error(cudaMalloc((void **)&xj_GPU, sizeof(float) * Nparticles));
    check_error(cudaMalloc((void **)&yj_GPU, sizeof(float) * Nparticles));
    check_error(cudaMalloc((void **)&CDF_GPU, sizeof(float) * Nparticles));
    check_error(cudaMalloc((void **)&u_GPU, sizeof(float) * Nparticles));
    check_error(cudaMalloc((void **)&likelihood_GPU, sizeof(float) * Nparticles));
    check_error(cudaMalloc((void **)&weights_GPU, sizeof(float) * Nparticles));
    check_error(cudaMalloc((void **)&I_GPU, sizeof(unsigned char) * IszX * IszY * Nfr));
    check_error(cudaMalloc((void **)&objxy_GPU, sizeof(int) * 2 * countOnes));
    check_error(cudaMalloc((void **)&ind_GPU, sizeof(int) * countOnes * Nparticles));
    check_error(cudaMalloc((void **)&seed_GPU, sizeof(int) * Nparticles));
    check_error(cudaMalloc((void **)&partial_sums_GPU, sizeof(float) * num_blocks));

    for (int x = 0; x < Nparticles; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    long long send_start = get_time();
    check_error(cudaMemcpy(I_GPU, I, sizeof(unsigned char) * IszX * IszY * Nfr, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(objxy_GPU, objxy, sizeof(int) * 2 * countOnes, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(weights_GPU, weights, sizeof(float) * Nparticles, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(xj_GPU, xj, sizeof(float) * Nparticles, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(yj_GPU, yj, sizeof(float) * Nparticles, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(seed_GPU, seed, sizeof(int) * Nparticles, cudaMemcpyHostToDevice));
    long long send_end = get_time();

    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_end));
    printf("threads_per_block=%d \n", threads_per_block);

    for (int k = 1; k < Nfr; k++) {
        likelihood_kernel<<<num_blocks, threads_per_block, threads_per_block * sizeof(float)>>>(
            arrayX_GPU, arrayY_GPU, xj_GPU, yj_GPU, ind_GPU, objxy_GPU, likelihood_GPU, I_GPU,
            weights_GPU, Nparticles, countOnes, max_size, k, IszY, Nfr, seed_GPU, partial_sums_GPU);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());

        sum_kernel<<<num_blocks, threads_per_block>>>(partial_sums_GPU, num_blocks);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());

        normalize_weights_kernel<<<num_blocks, threads_per_block>>>(weights_GPU, Nparticles, partial_sums_GPU);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());

        cdf_u_kernel<<<1, 1>>>(weights_GPU, Nparticles, CDF_GPU, u_GPU, seed_GPU);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());

        check_error(cudaMemcpy(arrayX, arrayX_GPU, sizeof(float) * Nparticles, cudaMemcpyDeviceToHost));
        check_error(cudaMemcpy(arrayY, arrayY_GPU, sizeof(float) * Nparticles, cudaMemcpyDeviceToHost));
        check_error(cudaMemcpy(weights, weights_GPU, sizeof(float) * Nparticles, cudaMemcpyDeviceToHost));

        xe = 0;
        ye = 0;
        float total = 0.0f;
        for (int x = 0; x < Nparticles; x++) {
            xe += arrayX[x] * weights[x];
            ye += arrayY[x] * weights[x];
            total += weights[x];
        }
        printf("total weight: %lf\n", total);
        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        float distance = sqrtf(powf((float)(xe - (int)roundFloat(IszY / 2.0f)), 2) +
                               powf((float)(ye - (int)roundFloat(IszX / 2.0f)), 2));
        printf("%lf\n", distance);

        find_index_kernel<<<num_blocks, threads_per_block>>>(
            arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, weights_GPU, Nparticles);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());
    }

    long long back_time = get_time();

    cudaFree(u_GPU);
    cudaFree(CDF_GPU);
    cudaFree(yj_GPU);
    cudaFree(xj_GPU);
    cudaFree(likelihood_GPU);
    cudaFree(I_GPU);
    cudaFree(objxy_GPU);
    cudaFree(ind_GPU);
    cudaFree(seed_GPU);
    cudaFree(partial_sums_GPU);

    long long free_time = get_time();

    check_error(cudaMemcpy(arrayX, arrayX_GPU, sizeof(float) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayX_time = get_time();
    check_error(cudaMemcpy(arrayY, arrayY_GPU, sizeof(float) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayY_time = get_time();
    check_error(cudaMemcpy(weights, weights_GPU, sizeof(float) * Nparticles, cudaMemcpyDeviceToHost));
    long long back_end_time = get_time();

    printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("SEND TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));

    xe = 0;
    ye = 0;
    for (int x = 0; x < Nparticles; x++) {
        xe += arrayX[x] * weights[x];
        ye += arrayY[x] * weights[x];
    }
    float distance = sqrtf(powf((float)(xe - (int)roundFloat(IszY / 2.0f)), 2) +
                           powf((float)(ye - (int)roundFloat(IszX / 2.0f)), 2));

    FILE *fid = fopen("output.txt", "w+");
    if (fid == NULL) {
        printf("The file was not opened for writing\n");
        return -1;
    }
    fprintf(fid, "XE: %lf\n", xe);
    fprintf(fid, "YE: %lf\n", ye);
    fprintf(fid, "distance: %lf\n", distance);
    fclose(fid);

    cudaFree(weights_GPU);
    cudaFree(arrayY_GPU);
    cudaFree(arrayX_GPU);

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);

    return 0;
}

static int run(int argc, char *argv[]) {
    const char *usage = "float.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles> [-p platform] [-d device]";

    if (argc < 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    for (int i = 9; i < argc; ++i) {
        switch (argv[i][1]) {
            case 'p':
                if (++i < argc) sscanf(argv[i], "%d", &platform_id_inuse);
                break;
            case 'd':
                if (++i < argc) sscanf(argv[i], "%d", &device_id_inuse);
                break;
            default:
                ;
        }
    }

    int *seed = (int *)calloc(Nparticles, sizeof(int));
    for (int i = 0; i < Nparticles; i++) seed[i] = i + 1;

    unsigned char *I = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));

    long long start = get_time();
    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}

